#include<bits/stdc++.h>
using namespace std;
int ax,ay,bx,by;
int id[261][261];
int dx[4]={1,0,-1,0};
int dy[4]={0,1,0,-1};
int a[261][261];
int tot;
int v[550][550][5];
int dis[5050][5050];
bool vis[5050][5050];
vector<int> mp[200010][5];
int main()
{
    int n,m,Q;
    scanf("%d%d%d",&n,&m,&Q);
    for(int i=1;i<=m;i++)
    {
        int x,y;
        scanf("%d%d",&x,&y);
        a[x][y]=1;
    }
    for(int i=0;i<=n+1;i++)
    {
        for(int j=0;j<=n+1;j++)
        {
            if(i==0||j==0||i==n+1||j==n+1)
            {
                a[i][j]=1;
            }
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)
        {
            for(int k=0;k<4;k++)
            {
                int x=i+dx[k],y=j+dy[k];
                if(a[x][y])
                {
                    id[i][j]=++tot;
                    break;
                }
            }
        }
    }
    for(int i=n;i>=1;i--)
    {
        for(int j=n;j>=1;j--)
        {
            if(!a[i][j+1])
            {
                v[i][j][1]=v[i][j+1][1];
            }
            else
            {
                v[i][j][1]=id[i][j];
            }
            if(!a[i+1][j])
            {
                v[i][j][2]=v[i+1][j][2];
            }
            else
            {
                v[i][j][2]=id[i][j];
            }
        }
    }
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)
        {
            if(!a[i][j-1])
            {
                v[i][j][3]=v[i][j-1][3];
            }
            else
            {
                v[i][j][3]=id[i][j];
            }
            if(!a[i-1][j])
            {
                v[i][j][4]=v[i-1][j][4];
            }
            else
            {
                v[i][j][4]=id[i][j];
            }
        }
    }
    queue<pair<int,int>> q;
    memset(dis,0x3f,sizeof(dis));
    for(int i=1;i<=n;i++)
    {
        for(int j=1;j<=n;j++)
        {
            if(id[i][j])
            {
                for(int k=1;k<=4;k++)
                {
                    mp[v[i][j][k]][k].push_back(id[i][j]);
                }
            }
        }
    }
    for(int i=1;i<=tot;i++)
    {
        vis[i][i]=true;
        dis[i][i]=1;
        q.push({i,i});
    }
    while(!q.empty())
    {
        int x=q.front().first,y=q.front().second;
        q.pop();
        for(int k=1;k<=4;k++)
        {
            for(int i:mp[x][k])
            {
                for(int j:mp[y][k])
                {
                    if(!vis[i][j])
                    {
                        vis[i][j]=true;
                        dis[i][j]=dis[x][y]+1;
                        q.push({i,j});
                    }
                }
            }
        }
    }
    while(Q--)
    {
        scanf("%d%d%d%d",&ax,&ay,&bx,&by);
        if(ax==bx&&ay==by)
        {
            printf("0\n");
            continue;
        }
        int ans=INT_MAX;
        for(int i=1;i<=4;i++)
        {
            ans=min(ans,dis[v[ax][ay][i]][v[bx][by][i]]);
        }
        if(ans>=1e9)
        {
            printf("-1\n");
        }
        else
        {
            printf("%d\n",ans);
        }
    }
    return 0;
}
